package com.huskydreaming.link.common;

import com.huskydreaming.link.common.configuration.DatabaseConfig;
import com.huskydreaming.link.common.configuration.DiscordConfig;
import com.huskydreaming.link.common.database.DatabaseConnector;
import com.huskydreaming.link.common.discord.DiscordClient;
import com.huskydreaming.link.common.discord.commands.SetupCommand;
import com.huskydreaming.link.common.discord.events.LinkEventBus;
import com.huskydreaming.link.common.discord.listeners.ButtonListener;
import com.huskydreaming.link.common.discord.listeners.ModalListener;
import com.huskydreaming.link.common.repositories.LinkRepository;
import com.huskydreaming.link.common.repositories.LinkRepositoryImpl;
import com.huskydreaming.link.common.services.implementations.CodeServiceImpl;
import com.huskydreaming.link.common.services.implementations.DiscordServiceImpl;
import com.huskydreaming.link.common.services.implementations.LinkServiceImpl;
import com.huskydreaming.link.common.services.interfaces.CodeService;
import com.huskydreaming.link.common.services.interfaces.DiscordService;
import com.huskydreaming.link.common.services.interfaces.LinkService;
import org.slf4j.Logger;

import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public abstract class LinkCommonPlugin {

    protected final ExecutorService executor = Executors.newFixedThreadPool(4);
    protected final LinkEventBus linkEventBus = new LinkEventBus(executor);

    protected CodeService codeService;
    protected DiscordService discordService;
    protected LinkRepository linkRepository;
    protected LinkService linkService;

    protected DiscordClient discordClient;
    protected DatabaseConnector databaseConnector;

    public void initialize(DatabaseConfig databaseConfig, DiscordConfig discordConfig, Logger logger) {
        databaseConnector = new DatabaseConnector(databaseConfig, logger);
        this.linkRepository = new LinkRepositoryImpl(databaseConnector);
        this.linkService = new LinkServiceImpl(linkRepository);
        this.linkService.initialize().exceptionally(ex -> {
            logger.error("Failed to initialize LinkService", ex);
            return null;
        });
        this.codeService = new CodeServiceImpl();

        this.discordClient = new DiscordClient(discordConfig);
        this.discordService = new DiscordServiceImpl(discordConfig, discordClient, logger);

        discordClient.getJda().addEventListener(
                new ButtonListener(),
                new SetupCommand(),
                new ModalListener(this, logger)
        );
    }

    public CodeService getCodeService() {
        return codeService;
    }

    public DiscordService getDiscordService() {
        return discordService;
    }

    public LinkEventBus getLinkEventBus() {
        return linkEventBus;
    }

    public LinkService getLinkService() {
        return linkService;
    }
}

